window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2018>1","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"Which of the following problems does not cause wastage of farm produce","images":[],"options":{"A":"use of crude farm tools","B":"poor transportation network","C":"inadequate processing facilities","D":"inadequate storage facilities"},"answer":"A","explanation":"The use of crude farm tools will only affect the efficiency of production, that is, it will reduce the speed needed to achieve a particular task.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>2","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : AGRICULTURAL MECHANIZATION","question":"Which of the following statements is not a reason for providing tractor-hiring services to farmers? To","images":[],"options":{"A":"encourage farm mechanization","B":"increase the area of land to be cultivated","C":"increase the cost of production","D":"boost food production"},"answer":"C","explanation":"Tractor-hiring services are provided to farmers to encourage farm mechanization, increase the area of land to be cultivated, and boost food production. These services are not provided to increase the cost of production. In fact, they often help to reduce the cost of production by making farming more efficient and productive.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>3","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"The land tenure system which involves the outright purchase of land is","images":[],"options":{"A":"leasehold","B":"communal","C":"freehold","D":"inheritance"},"answer":"C","explanation":"The land tenure system which involves the outright purchase of land is known as freehold. In a freehold system, the landowner has the right to use the land for any purpose, subject to local zoning laws, and may sell or pass the land to their heirs. This is different from leasehold, where the land is leased from the owner for a specific period of time; communal, where the land is owned and used by a community; and inheritance, where the land is passed down from generation to generation.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>4","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The diagram below illustrate a farm equipment. Study it and answer questions 4 and 5      The equipment is used for","images":["data:image/png;base64,"],"options":{"A":"watering","B":"pruning","C":"fertigation","D":"mulching"},"answer":"A","explanation":"The diagram displayed in the question is a watering apparatus.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>5","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The part of the equipment labelled I is used to","images":["data:image/png;base64,"],"options":{"A":"control pressure","B":"store liquid","C":"prevent leakage","D":"reduce liquid to droplets"},"answer":"D","explanation":"The part labelled I is used to control the amount of liquid that is ejected from the hose.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>6","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Which of the following devices is not a tractor- coupled implement?","images":[],"options":{"A":"Plough","B":"Sheller","C":"Ridger","D":"Harrow"},"answer":"B","explanation":"A Sheller is not a tractor-coupled implement. Tractor-coupled implements are devices that are attached to a tractor to perform various agricultural tasks. These include ploughs, which are used to prepare the soil for planting; ridgers, which are used to create ridges in the soil; and harrows, which are used to break up clods of soil and smooth the soil surface. A Sheller, on the other hand, is a machine used to remove the shells from nuts and grains, and is not typically attached to a tractor.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>7","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"Which of the following statement is not true of electrical power? It","images":[],"options":{"A":"can be generated from solar energy","B":"is the cleanest source of farm power","C":"can perform farm work on its own","D":"is capital intensive"},"answer":"C","explanation":"Electrical power cannot perform farm work on its own. It needs to be converted into mechanical power by machines or equipment to perform work. The other options are correct. Solar energy can be converted into electrical power. Electrical power is considered clean as it does not produce harmful emissions during operation. It is also capital intensive as the infrastructure needed to generate and distribute electrical power is expensive.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>8","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The survey equipment used for measuring angular distance is","images":[],"options":{"A":"offset staff","B":"measuring tape","C":"ranging pole","D":"prismatic compass"},"answer":"D","explanation":"A prismatic compass is used for measuring angular distances. It is a navigation and surveying instrument which is extensively used to find out the bearing of the traversing and included angles between them. The other options listed are not used for measuring angular distances. An offset staff is used for measuring vertical distances, a measuring tape is used for measuring linear distances, and a ranging pole is used for marking points in a line on the ground.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>9","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PRODUCTION : PASTURE AND FORAGE CROPS","question":"The practice of growing arable and forage crops alternately on a piece of land is called","images":[],"options":{"A":"ley farming","B":"mixed farming","C":"alley farming","D":"pastoral farming"},"answer":"A","explanation":"The practice of growing arable and forage crops alternately on a piece of land is called ley farming. This is a system of rotational farming in which the field is alternately seeded for grain and left fallow. Other options are incorrect. Mixed farming is a type of farming which involves both the growing of crops as well as the raising of livestock. Alley farming involves the planting of food crops in alleys between trees. Pastoral farming is a form of agriculture where livestock are raised on grassland.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>10","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"Which of the following of raw materials are used in textiles industries?","images":[],"options":{"A":"Guinea corn, wheat and kenaf","B":"cotton, jute and wool","C":"coffee, cotton and cocoa","D":"wool, palm kernel and maize"},"answer":"B","explanation":"Textile industries primarily use raw materials like cotton, jute, and wool. Cotton is used for making clothes, jute is used for making sacks, ropes, etc., and wool is used for making warm clothes. Therefore, the correct answer is 'cotton, jute and wool'.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>11","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"Which of the following is an example of igneous rock?","images":[],"options":{"A":"Basalt","B":"Dolomite","C":"limestone","D":"marble"},"answer":"A","explanation":"Igneous rocks are formed from the solidification of magma or lava. Basalt is an example of an igneous rock. Dolomite, limestone, and marble are examples of sedimentary and metamorphic rocks, not igneous rocks. Therefore, the correct answer is 'Basalt'.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2018>12","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"The chemical composition of soil is mostly influenced by","images":[],"options":{"A":"climate","B":"time","C":"topography","D":"parent material"},"answer":"D","explanation":"The chemical composition of soil is primarily influenced by the parent material. The parent material refers to the mineral material or organic material from which the soil is formed. The type of parent material determines the mineral composition of the soil and hence its chemical properties. Therefore, the correct answer is 'parent material'.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>13","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"The structure of loam could be described as","images":[],"options":{"A":"single-grained","B":"blocky","C":"crumby","D":"platy"},"answer":"C","explanation":"Loam soil is often described as crumby. This is because it has a balanced mixture of sand, silt, and clay, which gives it a crumbly texture. It is ideal for growing plants because it retains nutrients and water while still allowing excess water to drain away.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>14","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Study the diagram below and answer questions 14 and 15        The aim of the experiment illustration in the diagram is to","images":["data:image/png;base64,"],"options":{"A":"determine soil texture","B":"ascertain water content of soil","C":"examine the structure of soil","D":"determine soil acidity"},"answer":"B","explanation":"The aim of the experiment is to determine the water content of the soil, i.e. the water- retaining capacity of the soil.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2018>15","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Study the diagram below and answer questions 14 and 15      The purpose of the part labelled I in the experiment is to","images":["data:image/png;base64,"],"options":{"A":"allow proper aggregation of soil particles","B":"allow even evaporation of water","C":"prevent water from escaping","D":"distribute water around the soil"},"answer":"B","explanation":"The part labelled I is called a stirrer, which is used to allow even distribution of heat.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2018>16","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRICULTURAL POLLUTION","question":"A beneficial effect of bush burning on the soil is the","images":[],"options":{"A":"reduction of soil microbial activities","B":"exposure of soil surface to erosion","C":"destruction of weed seeds","D":"destruction of soil organic matter"},"answer":"C","explanation":"Bush burning can destroy weed seeds. The heat from the fire can cause the seeds to burst or become non-viable, reducing the number of weeds in the area. However, it's important to note that bush burning can also have negative effects on the soil and environment, such as reducing soil fertility and causing air pollution.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>17","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Which of the following practices does not replenish lost soil nutrients?","images":[],"options":{"A":"crop rotation","B":"fallowing","C":"liming","D":"bush burning"},"answer":"D","explanation":"Bush burning does not replenish lost soil nutrients. In fact, it often leads to the loss of nutrients as they are destroyed by the heat or washed away by rain after the protective vegetation cover has been removed. Practices like crop rotation, fallowing, and liming can help to replenish soil nutrients.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>18","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The use of inorganic fertilizer is preferable to organic manure because inorganic fertilizer","images":[],"options":{"A":"improves soil structure","B":"releases nutrients to the soil faster","C":"reduces leaching of soil nutrients","D":"improves soil water holding capacity"},"answer":"B","explanation":"Inorganic fertilizers are mineral salts that are quickly absorbed by plants. They release nutrients to the soil faster than organic manure. Organic manure, on the other hand, improves soil structure and water holding capacity, and reduces leaching of soil nutrients.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>19","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"Which of the following statements describes an advantage of underground drainage? It","images":[],"options":{"A":"allows for free movement of farm machinery","B":"checks the growth of weeds","C":"improve soil texture","D":"increases organic matter content of soil"},"answer":"A","explanation":"Underground drainage systems are designed to remove excess water from the soil surface. This allows for free movement of farm machinery, as the soil is not waterlogged. It does not directly check the growth of weeds, improve soil texture, or increase organic matter content of soil.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2018>20","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Which of the following crops usually classified as a vegetable?","images":[],"options":{"A":"lycopersicon esculentum","B":"Ananas sativa","C":"Hevea brasiliensis","D":"Theobroma cacao"},"answer":"A","explanation":"Lycopersicon esculentum  is the scientific name for tomato, which is usually classified as a vegetable.  Ananas sativa (pineapple),  Hevea brasiliensis (rubber tree), and  Theobroma cacao (cacao tree) are not typically classified as vegetables.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>21","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"A groundnut variety produces a steady seed yield of 350 kg per hectare. What will be the yield of the variety on a 10-hectare farm?","images":[],"options":{"A":"35 kg","B":"350 kg","C":"3,500 kg","D":"7,000 kg"},"answer":"C","explanation":"From the information given in the question,   The yield per hectare is 350kg, it implies that 10 hectare will yield 350 \u00d7 10 = 3500kg","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2018>22","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Thinning is a farm operation in which","images":[],"options":{"A":"empty spaces where seeds did not germinate are replanted","B":"the number of seedlings per stand is reduced to one or two","C":"fertilizers and manures are applied to crops.","D":"effort is made to control pests"},"answer":"B","explanation":"Thinning is a process that involves the reduction of the number of seedlings per stand to one or two.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>23","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PRODUCTION : PASTURE AND FORAGE CROPS","question":"Which of the following plants is not a pasture grass?","images":[],"options":{"A":"Pennisetum purpureum","B":"Axonopus compressus","C":"Stylosanthes gracilis","D":"Panicum maximum"},"answer":"C","explanation":"Stylosanthes gracilis  is not a pasture grass but a legume. It is often used in pastures for its high protein content and ability to fix nitrogen in the soil. The other options,  Pennisetum purpureum ,  Axonopus compressus , and  Panicum maximum , are all types of pasture grasses. Hence, the correct option is  'Stylosanthes gracilis'.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2018>24","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"One advantage of cross breeding is that the","images":[],"options":{"A":"offspring resemble the recessive parent","B":"yield of the offspring may not be comparable to those of the parents","C":"offspring perform better than the average of the parents","D":"offspring cannot survive adverse environmental conditions"},"answer":"C","explanation":"Cross breeding is an advantage because the offspring performs better than the average of the parents.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>25","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"Assuming that brown colour is dominant over black colour in cowpea. What percentage of the F1 generation will have brown colour, if a homozygous brown cowpea is crossed with a homozygous black cowpea?","images":[],"options":{"A":"100%","B":"75%","C":"50%","D":"25%"},"answer":"A","explanation":"In genetics, when a homozygous dominant trait (brown colour) is crossed with a homozygous recessive trait (black colour), all of the first generation (F1) offspring will exhibit the dominant trait. This is because the dominant allele will mask the expression of the recessive allele. Therefore, 100% of the F1 generation will have brown colour.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>26","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ORNAMENTAL PLANTS :","question":"Ornamental plants are commonly used for the following purpose except","images":[],"options":{"A":"for exterior decorations","B":"as sources of perfumes","C":"provision of shade","D":"as bedding materials for animals"},"answer":"D","explanation":"Ornamental plants are primarily used for decorative purposes, such as exterior decorations and provision of shade. They can also be used as sources of perfumes. However, they are not typically used as bedding materials for animals. Bedding materials for animals are usually made from straw, hay, wood shavings, or other similar materials.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2018>27","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ORNAMENTAL PLANTS :","question":"Hibiscus and croton are examples of","images":[],"options":{"A":"ground covers","B":"hedge plants","C":"lawn plants","D":"avenue trees"},"answer":"B","explanation":"Hibiscus and croton are examples of hedge plants.   A hedge is a row of bushes or small trees planted close together.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2018>28","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"A disadvantage of vegetative propagation is that","images":[],"options":{"A":"plants are true to type","B":"fruits are small in size","C":"plants take a long time to mature","D":"diseases are easily transferred to offspring"},"answer":"D","explanation":"A disadvantage of vegetative propagation is that diseases are easily transferred to offspring. Vegetative propagation is a form of asexual reproduction in plants. It is a faster and more certain method than sexual reproduction, but it has the disadvantage of transferring diseases from the parent plant to the offspring. The other options are not disadvantages. Plants being true to type means that they retain the characteristics of the parent plant, which is usually a desirable trait. Fruits being small in size and plants taking a long time to mature are not related to vegetative propagation.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>29","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"An effective method of preventing viral diseases in crops is by","images":[],"options":{"A":"treating the seeds with fungicides","B":"practising crop rotation","C":"regular spraying of crops","D":"planting resistant varieties"},"answer":"D","explanation":"An effective method of preventing viral diseases in crops is by planting resistant varieties. Viral diseases in plants are often spread by insects or other organisms, and they can also be spread by wind, rain, or human activity. Planting resistant varieties is a way to prevent these diseases, as these plants have been bred or genetically modified to resist specific diseases. Treating the seeds with fungicides is not effective against viral diseases, as fungicides are used to prevent fungal diseases. Practising crop rotation and regular spraying of crops can help prevent some diseases, but they are not specifically effective against viral diseases.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>30","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"A groundnut plant showing stunted growth with yellow or mottled leaves is likely to be infected with","images":[],"options":{"A":"blight","B":"tikka","C":"rosette","D":"anthracnose"},"answer":"C","explanation":"The symptoms described in the question are characteristic of the groundnut rosette disease. This disease is caused by a virus and is characterized by stunted growth and yellow or mottled leaves. None of the other options (blight, tikka, anthracnose) typically cause these symptoms in groundnut plants.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>31","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"The diagram below illustrates a crop pest. Study it and answer questions 31 and 32.        The pest illustrated is a","images":["data:image/png;base64,"],"options":{"A":"boring insect pest","B":"chewing insect pest","C":"sucking insect pest","D":"piercing insect pest"},"answer":"B","explanation":"The mouth part of the insect depicts that it is a chewing insect pest.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>32","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"The diagram below illustrates a crop pest. Study it and answer questions 31 and 32.      A cultural method used in controlling the pest illustrated is","images":["data:image/png;base64,"],"options":{"A":"spraying with insecticides","B":"hand pulling of weeds","C":"fumigation of store","D":"early planting"},"answer":"A","explanation":"The cultural method which will best  control the pest is by spraying with insecticide.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>33","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below illustrates the digestive tract of a farm animal. Study it and answer questions 33 and 34        Deamination is a function of the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"D","explanation":"Deamination is a biological process that takes place in the liver. Deamination involves the breakdown of excess amino acids. This process is crucial for the metabolism of amino acids in the body, helping to eliminate excess nitrogen and convert amino acids into usable energy. Part labelled IV is liver.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>34","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below illustrates the digestive tract of a farm animal. Study it and answer questions 33 and 34      Digestion of protein starts in the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"The part labelled I is stomach which secretes several gastric biochemicals such as HCl, gastric lipase and pepsin. Pepsin is used in the initial breakdown of proteins to peptides.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>35","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Study the diagram below and answer questions 35 and 36        Fertilization takes place in the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"Fertilization takes place in the part labelled I, i.e. the infundibulum","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>36","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Study the diagram below and answer questions 35 and 36      Chalaza is formed in the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"D","explanation":"Chalaza is formed at IV, i.e. the ampulla. The chalaza is formed in the ampulla, which is part of the hen's reproductive tract where the egg white (albumen) begins to form around the yolk.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>37","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"A farmer observed that all his day-old chicks clustered around the source of heat in a brooder house. This observation is likely due to","images":[],"options":{"A":"manifestation of a disease outbreak","B":"thirst because of inadequate of water","C":"poor nutrition","D":"low temperature"},"answer":"D","explanation":"Low temperature (depletion of heat) has made the organisms to source for an alternative source of heat.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>38","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Which of the following practices ensure that a young animal has resistance against diseases?","images":[],"options":{"A":"Regular visits of the veterinary doctors","B":"Giving the animal a maintenance ration","C":"Regular dipping of animal","D":"Giving the animal access to colostrum"},"answer":"D","explanation":"Giving a young animal access to colostrum is the best way to ensure it has resistance against diseases. Colostrum is the first milk produced by a mother after giving birth, and it is rich in antibodies that provide passive immunity to the newborn. The other options (regular veterinary visits, maintenance ration, regular dipping) are important for overall health and well-being, but they do not directly provide disease resistance.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>39","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Study the diagram below and answer question 39 and 40       The animal by-product illustrated may be prepared and fed to farm animals as a source of","images":["data:image/png;base64,"],"options":{"A":"sodium","B":"iron","C":"calcium","D":"nitrogen"},"answer":"C","explanation":"The displayed diagram depicts bones, which are sources of calcium.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>40","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Study the diagram below and answer question 39 and 40     The animal by-product illustrated is not used in making","images":["data:image/png;base64,"],"options":{"A":"fertilizer","B":"bone meal","C":"button","D":"leather"},"answer":"D","explanation":"Bone is not used in making leather. Bone is not used in the traditional process of making leather. Leather is primarily made from the hides or skins of animals, particularly cattle, goats, sheep, and pigs.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2018>41","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Vitamin K deficiency in farm animals causes","images":[],"options":{"A":"night blindness","B":"sterility in both sexes","C":"delayed blood clothing","D":"delayed ovulation"},"answer":"C","explanation":"Vitamin K is essential for the synthesis of certain proteins required for blood clotting. Without it, blood clotting is impaired, leading to excessive bleeding. Therefore, a deficiency of Vitamin K in farm animals causes delayed blood clotting.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>42","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Which of the following methods is not used in collecting semen from artificial insemination","images":[],"options":{"A":"Message method","B":"Use of artificial vagina","C":"Herd mating of the animals","D":"Electro-ejaculation method"},"answer":"C","explanation":"Artificial insemination is a process where semen is collected from a male animal and then manually inserted into the female's reproductive tract. The methods used for collecting semen include the massage method, use of an artificial vagina, and the electro-ejaculation method. Herd mating of the animals is not a method used in collecting semen for artificial insemination as it involves natural mating.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>43","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Complete eradication of tsetse flies will be an effective control measure for","images":[],"options":{"A":"aspergillosis","B":"trypanosomiasis","C":"fowl pox","D":"swine fever"},"answer":"B","explanation":"Tse tse fly is the transmitting vector for sleeping sickness (trypanosomiasis), hence its complete extermination will reduce the incidence of the disease.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>44","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Which of the following diseases is caused by a virus?","images":[],"options":{"A":"Brucellosis","B":"Trypanosomiasis","C":"Rinderpest","D":"Tuberculosis"},"answer":"C","explanation":"Rinderpest is a viral disease that affects cloven-hoofed animals, including cattle and pigs. The other diseases listed are caused by bacteria (Brucellosis and Tuberculosis) and protozoa (Trypanosomiasis).","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>45","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"ANIMAL PRODUCTION : APICULTURE OR BEE KEEPING","question":"Bees are regarded as friends of the farmer because they","images":[],"options":{"A":"usually sting the farmer","B":"are harmless insects","C":"help in pollination","D":"produce nectar for human use"},"answer":"C","explanation":"Bees are popularly called the friends of farmers because they assist in pollination, i.e. they assist in the transfer of pollen grains from anther to stigma.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2018>46","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"Use the demand schedule below to answer questions 46, 47 and 48  Price (\u20a6)Quantity Demanded (kg)122008240    What is the percentage change in quantity demanded?","images":[],"options":{"A":"16.67%","B":"20.00%","C":"40.00%","D":"83.33%"},"answer":"B","explanation":"From the information given in the table,   Q2 = 240  Q1 = 200  Change in the quantity demanded = Q2 - Q1 = 40.  % change in the quantity demanded =( 40/200) \u00d7 100 = 20%","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2018>47","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"Use the demand schedule below to answer questions 46, 47 and 48  Price (\u20a6)Quantity Demanded (kg)122008240  What is the percentage change in price?","images":[],"options":{"A":"33.33%","B":"40.00%","C":"50.00%","D":"66.67%"},"answer":"A","explanation":"From the information given in the question,   P1 = #12  P2 = #8  Change in price of commodity = P2 - P1 = #4  % Change in the price of commodity =  (4/12) \u00d7 100 = 33.3%","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2018>48","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"Use the demand schedule below to answer questions 46, 47 and 48  Price (\u20a6)Quantity Demanded (kg)122008240  What is the price elasticity of demand of the commodity?","images":[],"options":{"A":"0.3","B":"0.4","C":"0.5","D":"0.6"},"answer":"D","explanation":"Recall that : Price elasticity of demand = (\u03b4QtyDd/\u03b4P) \u00d7 P1/Q1   = (Q2 - Q1) \u00d7 P1/Q1   = (240 - 200)/4 \u00d7 12/200   = (40/4) \u00d7 (12/200)   =0.6","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2018>49","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"Which of the following farm documents is usually prepared at the end of the year","images":[],"options":{"A":"farm budget","B":"labour record","C":"farm inventory","D":"profit and loss account"},"answer":"D","explanation":"The profit and loss account is prepared at the end of the business year. It is done to know wether or not the company makes an appreciable profit or loss.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2018>50","subject":"Agricultural Science","year":"2018","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"Which of the following agricultural extension methods is aimed at reaching an individual farmer at a particular time?","images":[],"options":{"A":"film show","B":"farm visit","C":"electronic media","D":"field trip"},"answer":"B","explanation":"A farm visit is an agricultural extension method that is aimed at reaching an individual farmer at a particular time. This is because during a farm visit, the extension officer visits the farmer on his farm, interacts with him one-on-one, and provides him with the necessary advice and guidance. Other options like film show, electronic media, and field trip are usually aimed at reaching a group of farmers at the same time.","marks":"1","difficulty":"2"}];